let StripeModel={creditcard:{async createCreditCard(data){let payload={email:data.email,stripe_credit_card:data.creditcard},response=await StripeServices.createCreditCard({payload:payload});return response.state?response:(App.events.notyf("error","Failed to create creditcard"),response)},async removeCreditCard(id){let payload={id:id,properties:{is_enabled:!1}},response=await StripeServices.updateCreditCard({payload:payload});return response.state?response:(App.events.notyf("error","Failed to delete creditcard"),response)},async updateCreditCard(payload){let response=await StripeServices.updateCreditCard({payload:payload});return response.state?response:(App.events.notyf("error","Failed to update creditcard"),response)}},customer:{}};window.StripeModel=StripeModel;